import React, { useState } from "react";

export default function SignUpScreen({ onSignUp }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleSignUp = () => {
    if (!name || !email || !password) return alert("All fields are required");
    onSignUp({ name, email, password });
  };

  return (
    <div className="w-screen h-screen flex flex-col justify-center px-6 bg-gray-50">
      <h1 className="text-3xl font-bold mb-8 text-center">Sign Up</h1>
      <input
        type="text"
        placeholder="Full Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        className="w-full p-3 mb-4 rounded-xl border"
      />
      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        className="w-full p-3 mb-4 rounded-xl border"
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        className="w-full p-3 mb-6 rounded-xl border"
      />
      <button
        onClick={handleSignUp}
        className="w-full py-3 bg-teal-600 text-white rounded-xl hover:bg-teal-700 transition-colors"
      >
        Create Account
      </button>
    </div>
  );
}
